// Parse Shopify order webhook payload
const order = $input.first().json;

const customer = order.customer || {};
const shippingAddress = order.shipping_address || order.billing_address || {};
const lineItems = order.line_items || [];

// Build items list for email
const itemsList = lineItems.map(item => 
  `• ${item.name} × ${item.quantity} — €${parseFloat(item.price).toFixed(2)}`
).join('\n');

// Calculate estimated delivery (5-7 business days from now)
const deliveryDate = new Date();
deliveryDate.setDate(deliveryDate.getDate() + 6);
const deliveryDateStr = deliveryDate.toLocaleDateString('en-GB', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });

// Review request date = delivery date + 3 days
const reviewDate = new Date(deliveryDate);
reviewDate.setDate(reviewDate.getDate() + 3);

return [{
  json: {
    order_id: order.id || order.order_number,
    order_number: order.order_number || order.name,
    customer_email: customer.email || order.email,
    customer_name: `${customer.first_name || ''} ${customer.last_name || ''}`.trim() || 'Valued Customer',
    customer_phone: shippingAddress.phone || customer.phone || '',
    total_price: order.total_price || '0.00',
    currency: order.currency || 'EUR',
    items_list: itemsList,
    items_count: lineItems.length,
    shipping_address: `${shippingAddress.address1 || ''}, ${shippingAddress.city || ''}, ${shippingAddress.country || ''}`,
    estimated_delivery: deliveryDateStr,
    review_request_date: reviewDate.toISOString(),
    order_status_url: order.order_status_url || `https://REPLACE_WITH_SHOP_DOMAIN/orders/${order.id}`,
    created_at: order.created_at || new Date().toISOString(),
    _raw_order_id: order.id
  }
}];

// Parse abandoned cart data
const cart = $input.first().json;
const customer = cart.customer || {};
const lineItems = cart.line_items || cart.checkout?.line_items || [];

const itemsList = lineItems.map(item =>
  `• ${item.title || item.name} × ${item.quantity}`
).join('\n');

const recoveryUrl = cart.abandoned_checkout_url || 
                    cart.checkout?.abandoned_checkout_url || 
                    `https://REPLACE_WITH_SHOP_DOMAIN/cart`;

return [{
  json: {
    customer_email: customer.email || cart.email || cart.checkout?.email,
    customer_name: `${customer.first_name || cart.checkout?.billing_address?.first_name || ''}`.trim() || 'there',
    items_list: itemsList || 'Your saved items',
    cart_total: cart.total_price || cart.checkout?.total_price || '0.00',
    currency: cart.currency || cart.checkout?.currency || 'EUR',
    recovery_url: recoveryUrl,
    cart_id: cart.id || cart.checkout?.id,
    created_at: new Date().toISOString()
  }
}];

const error = $input.first().json;
console.error('ME-08 Error:', JSON.stringify(error));
return [{ json: { error: true, message: error.message || 'Unknown error', timestamp: new Date().toISOString() } }];
